export function getEuPlate(country: string): boolean | null {
  return country in euPlateData ? euPlateData[country] : null;
}

export function getCameraGens(country: string): CameraGen[] {
  return cameraGenData[country] ?? [];
}

export function getCoverageYears(country: string): number[] {
  return coverageYearsData[country] ?? [];
}

export function getCarColors(country: string): CarColor[] {
  return carColorData[country] ?? ['white'];
}

export function getVehicleType(country: string): VehicleType {
  return vehicleTypeData[country] ?? 'car';
}
